#include <bits/stdc++.h>
using namespace std;
int n,w,a[605];
int main(){
	cin>>n>>w;
	for(int i=1;i<=n;i++){
		int x; 
		cin>>x;
		a[x]++;
		int l=max(1,i*w/100);
		int sum=0;
		for(int j=600;j>=0;j--){
			if(a[j]){
				sum+=a[j];
				if(sum>=l){
					cout<<j<<" ";
					break;
				} 
			}
		}
	}
	return 0;
}
